import React, { useState } from 'react'
import './Work.css'

function Work(props) {
 
  const [htmlP, setHtmlP] = useState(true);
  const [reactP, setReactP] = useState(false);
  const [bootP, setBootP] = useState(false);
  


  const handleClick1 = () =>{
    if(htmlP === false){
        props.handleProjects1();
        setHtmlP(true)
        setReactP(false)
        setBootP(false)
    }
    else{}
  }
  const handleClick2 = () =>{
    if(reactP === false){
        props.handleProjects2();
        setHtmlP(false)
        setReactP(true)
        setBootP(false)
    }
    else{}
  }

  const handleClick3 = () =>{
    if(bootP === false){
        props.handleProjects3();
        setHtmlP(false)
        setReactP(false)
        setBootP(true)
    }
    else{}
  }
  

    return (
        <section className="work">

          <div className="work-title-con">
            <div className="work-title">Portfolio</div>
            <div className="line"></div>
          </div>

          <div className="work-types">
              <button onClick={handleClick1}>HTML/css/js</button>
              <button onClick={handleClick2}>ReactJS</button>
              <button onClick={handleClick3}>BOOTSTRAP</button>  

              
          </div>
          
        </section>
    )
}

export default Work
