import React from 'react'
import './Nav.css'
import './Nav-res.css'
import { Link } from 'react-router-dom'
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { faAlignJustify } from '@fortawesome/free-solid-svg-icons'

const element = <FontAwesomeIcon icon={faAlignJustify} />

const showMenu = () => {
    document.querySelector("#drd").classList.toggle("nav-toggle");
  }

function Nav() {
  return (
    <nav>
      <div className="nav-container">
        <div className="logo-con"><Link to="/" className="logo">Jimmy</Link></div>
        <div>
          <Link to="/" className="link">Home</Link>
          <Link to="/portfolio" className="link">Portfolio</Link>
        </div>
        
        <button type="button" onClick={()=> showMenu()} className="nav-icon">{element}</button>

      </div>

      <div id="drd" className="nav-dropDown">
                    <Link className="nav-link2" to="/">Home</Link >
                    <Link className="nav-link2" to="./Portfolio">Portfolio</Link>
                </div>

    </nav>
  )
}

export default Nav
