import React from 'react'
import './Contact.css'

function Contact() {
    return (
        <section className="contact">
            <div className="liar2">
                <div className="contact-container">
                    <div className="contact-title-con"><span className="contact-title">Contact</span></div>
                     <div className="contact-info">
                        <div>You can contact with me by sending a message to my account on Facebook</div> 
                     </div>
                </div>
            </div>
        </section>
    )
}

export default Contact
