import React, {useState} from 'react'
import './Header.css'
 

function Header() {


    const wheight = window.innerHeight
    const [height, setHeight] = useState(wheight)

    const handleResize = () =>{
        setHeight(window.innerHeight);
    }

window.addEventListener('resize', handleResize)
    


    return (
        <header className="header" id="headee" style={{height: height}}>
            <div className="header-img" style={{backgroundImage: `url(https://firebasestorage.googleapis.com/v0/b/jimmy-portfolio.appspot.com/o/bg.jpg?alt=media&token=fe69b092-7eec-45c8-8c02-f9e3a856183d)`}}>
                <div className="liar1">
                    <div className="header-intro">
      
                           <div className="intro">
                               <span> Hi, I am </span>
                               <span className="high-light">Ahmed Gamal</span>
                               <div className="intro2">Front-end developer</div>
                            </div>
                           
                    </div>
                    <a className="header-icon" href="#About"><span style={{display: `none`}}>Go to About</span> </a>
                </div>
            </div>
        </header>
    )
}

export default Header
