import db from './firebase.config';
import React, {useState, useEffect} from 'react'
import Project from './Project/Project'
import Nav from './Nav/Nav'
import Work from './Work/Work'




function Portfolio() {
    

  const [collection, setCollection] = useState('projects-html');
  const [projects,setProjects]=useState([])
  
  const fetchProjects=async()=>{
    const response=db.collection(collection);
    const data=await response.get();
    data.docs.forEach(item=>{
     setProjects([...projects,item.data()])
    })
  }
  
  
  useEffect(() => {
      fetchProjects();
    }, [collection])

      const handleProjects1 = () =>{
        setProjects([])
        setCollection('projects-html');
        fetchProjects()
      }
      
      const handleProjects2 = () =>{
        setProjects([])
        setCollection('projects-react');
        fetchProjects()
    }

      const handleProjects3 = () =>{
        setProjects([])
        setCollection('projects-bootstrap');
        fetchProjects()
    }
    
      const projectsList = projects.map((project, id) =>
      
          <div key={id} className="pic-con" style={{backgroundImage: `url(${project.pic})`}}>
                    <div className="liar3">
                       <div className="web-con">
                        <span className="pic-title">{project.name}</span>
                        <a href={project.li} rel="noreferrer" target="_blank" className="web-link">{project.visit}</a> 
                       </div>
                    </div>
                  </div>
      );
    
      
    return (
        <div>
            <Nav/>
            <Work 
            handleProjects1={handleProjects1}
            handleProjects2={handleProjects2}
            handleProjects3={handleProjects3}
            />
            <div  className="projects-con"  >
            <Project  projectsList={projectsList}/>
            </div>
        </div>
    )
}

export default Portfolio
